import React, { useState, useEffect } from "react"

const PRODUCTS = [
    "Fiber Internet 300 Mbps",
    "5G Unlimited Mobile Plan",
    "Fiber Internet 1 Gbps",
    "Business Internet 500 Mbps",
    "VoIP Corporate Package"
]

const UNIT_PRICES = {
    "Fiber Internet 300 Mbps": 49.99,
    "5G Unlimited Mobile Plan": 39.99,
    "Fiber Internet 1 Gbps": 89.99,
    "Business Internet 500 Mbps": 129.99,
    "VoIP Corporate Package": 199.99
}

const COUNTRIES = ["United States", "Canada", "Australia", "Singapore", "Hong Kong"]

const CREATORS = [
    "Mr. Michael Harris",
    "Mr. Ryan Cooper",
    "Ms. Olivia Carter",
    "Mr. Lucas Martin"
]

const INITIAL_FORM = {
    firstName: "",
    lastName: "",
    email: "",
    phone: "",
    streetAddress: "",
    city: "",
    state: "",
    postalCode: "",
    country: "",
    product: "",
    quantity: 1,
    unitPrice: "",
    totalAmount: "",
    status: "Pending",
    createdBy: ""
}

const REQUIRED_FIELDS = [
    "firstName", "lastName", "email", "phone",
    "streetAddress", "city", "state", "postalCode", "country",
    "product", "quantity", "unitPrice", "status", "createdBy"
]

function OrderForm({ onClose, onSave, initialData }) {
    const [form, setForm] = useState(INITIAL_FORM)
    const [errors, setErrors] = useState({})

    useEffect(() => {
        if (initialData) {
            setForm({ ...INITIAL_FORM, ...initialData })
        } else {
            setForm(INITIAL_FORM)
        }
    }, [initialData])

    const handleChange = (field, value) => {
        setErrors(prev => prev[field] ? { ...prev, [field]: "" } : prev)
        setForm(prev => {
            const updated = { ...prev, [field]: value }

            if (field === "product") {
                const price = UNIT_PRICES[value] || ""
                updated.unitPrice = price
                updated.totalAmount = price ? (Number(updated.quantity) * price).toFixed(2) : ""
            }

            if (field === "quantity") {
                const qty = Math.max(1, Number(value))
                updated.quantity = qty
                if (updated.unitPrice) {
                    updated.totalAmount = (qty * Number(updated.unitPrice)).toFixed(2)
                }
            }

            return updated
        })
    }

    const validate = () => {
        const newErrors = {}
        REQUIRED_FIELDS.forEach(field => {
            const val = form[field]
            if (val === "" || val === null || val === undefined) {
                newErrors[field] = "Please fill the field"
            }
        })
        return newErrors
    }

    const handleSubmit = () => {
        const newErrors = validate()
        if (Object.keys(newErrors).length > 0) {
            setErrors(newErrors)
            return
        }
        onSave(form)
    }

    const err = (name) => errors[name] ? (
        <span className="form-error">{errors[name]}</span>
    ) : null

    const inputCls = (name) => `form-control${errors[name] ? " error" : ""}`

    return (
        <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
            <div className="modal">
                <div className="modal-header">
                    <h3>{initialData ? "Edit Order" : "Create Order"}</h3>
                    <button className="btn-icon" onClick={onClose}>Ō£Ģ</button>
                </div>

                <div className="modal-body">
                    {/* ŌöĆŌöĆ Customer Information ŌöĆŌöĆ */}
                    <div className="settings-section-title" style={{ marginBottom: 14 }}>
                        Customer Information
                    </div>
                    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "0 16px" }}>

                        {/* First name */}
                        <div className="form-group">
                            <label className="form-label">First name <span className="required">*</span></label>
                            <input
                                type="text"
                                className={inputCls("firstName")}
                                value={form.firstName}
                                onChange={e => handleChange("firstName", e.target.value)}
                                autoComplete="off"
                            />
                            {err("firstName")}
                        </div>

                        {/* Last name */}
                        <div className="form-group">
                            <label className="form-label">Last name <span className="required">*</span></label>
                            <input
                                type="text"
                                className={inputCls("lastName")}
                                value={form.lastName}
                                onChange={e => handleChange("lastName", e.target.value)}
                                autoComplete="off"
                            />
                            {err("lastName")}
                        </div>

                        {/* Email */}
                        <div className="form-group">
                            <label className="form-label">Email ID <span className="required">*</span></label>
                            <input
                                type="email"
                                className={inputCls("email")}
                                value={form.email}
                                onChange={e => handleChange("email", e.target.value)}
                                autoComplete="off"
                            />
                            {err("email")}
                        </div>

                        {/* Phone */}
                        <div className="form-group">
                            <label className="form-label">Phone number <span className="required">*</span></label>
                            <input
                                type="text"
                                className={inputCls("phone")}
                                value={form.phone}
                                onChange={e => handleChange("phone", e.target.value)}
                                autoComplete="off"
                            />
                            {err("phone")}
                        </div>

                        {/* Street Address ŌĆö full width */}
                        <div className="form-group" style={{ gridColumn: "1 / -1" }}>
                            <label className="form-label">Street Address <span className="required">*</span></label>
                            <input
                                type="text"
                                className={inputCls("streetAddress")}
                                value={form.streetAddress}
                                onChange={e => handleChange("streetAddress", e.target.value)}
                                autoComplete="off"
                            />
                            {err("streetAddress")}
                        </div>

                        {/* City */}
                        <div className="form-group">
                            <label className="form-label">City <span className="required">*</span></label>
                            <input
                                type="text"
                                className={inputCls("city")}
                                value={form.city}
                                onChange={e => handleChange("city", e.target.value)}
                                autoComplete="off"
                            />
                            {err("city")}
                        </div>

                        {/* State */}
                        <div className="form-group">
                            <label className="form-label">State / Province <span className="required">*</span></label>
                            <input
                                type="text"
                                className={inputCls("state")}
                                value={form.state}
                                onChange={e => handleChange("state", e.target.value)}
                                autoComplete="off"
                            />
                            {err("state")}
                        </div>

                        {/* Postal code */}
                        <div className="form-group">
                            <label className="form-label">Postal code <span className="required">*</span></label>
                            <input
                                type="text"
                                className={inputCls("postalCode")}
                                value={form.postalCode}
                                onChange={e => handleChange("postalCode", e.target.value)}
                                autoComplete="off"
                            />
                            {err("postalCode")}
                        </div>

                        {/* Country */}
                        <div className="form-group">
                            <label className="form-label">Country <span className="required">*</span></label>
                            <select
                                className={inputCls("country")}
                                value={form.country}
                                onChange={e => handleChange("country", e.target.value)}
                            >
                                <option value="">Select country</option>
                                {COUNTRIES.map(c => <option key={c} value={c}>{c}</option>)}
                            </select>
                            {err("country")}
                        </div>
                    </div>

                    {/* ŌöĆŌöĆ Order Information ŌöĆŌöĆ */}
                    <div className="settings-section-title" style={{ marginBottom: 14, marginTop: 8 }}>
                        Order Information
                    </div>
                    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "0 16px" }}>

                        {/* Product ŌĆö full width */}
                        <div className="form-group" style={{ gridColumn: "1 / -1" }}>
                            <label className="form-label">Choose product <span className="required">*</span></label>
                            <select
                                className={inputCls("product")}
                                value={form.product}
                                onChange={e => handleChange("product", e.target.value)}
                            >
                                <option value="">Select product</option>
                                {PRODUCTS.map(p => <option key={p} value={p}>{p}</option>)}
                            </select>
                            {err("product")}
                        </div>

                        {/* Quantity */}
                        <div className="form-group">
                            <label className="form-label">Quantity <span className="required">*</span></label>
                            <input
                                type="number"
                                className={inputCls("quantity")}
                                value={form.quantity}
                                min={1}
                                onChange={e => handleChange("quantity", e.target.value)}
                            />
                            {err("quantity")}
                        </div>

                        {/* Unit price */}
                        <div className="form-group">
                            <label className="form-label">Unit price <span className="required">*</span></label>
                            <div style={{ position: "relative" }}>
                                <span style={{
                                    position: "absolute", left: 12, top: "50%",
                                    transform: "translateY(-50%)", color: "var(--text-secondary)"
                                }}>$</span>
                                <input
                                    type="text"
                                    className="form-control"
                                    style={{ paddingLeft: 28 }}
                                    value={form.unitPrice}
                                    readOnly
                                />
                            </div>
                            {err("unitPrice")}
                        </div>

                        {/* Total amount ŌĆö full width */}
                        <div className="form-group" style={{ gridColumn: "1 / -1" }}>
                            <label className="form-label">Total amount</label>
                            <div style={{ position: "relative" }}>
                                <span style={{
                                    position: "absolute", left: 12, top: "50%",
                                    transform: "translateY(-50%)", color: "var(--text-secondary)"
                                }}>$</span>
                                <input
                                    type="text"
                                    className="form-control"
                                    style={{ paddingLeft: 28 }}
                                    value={form.totalAmount}
                                    readOnly
                                />
                            </div>
                        </div>

                        {/* Status */}
                        <div className="form-group">
                            <label className="form-label">Status <span className="required">*</span></label>
                            <select
                                className={inputCls("status")}
                                value={form.status}
                                onChange={e => handleChange("status", e.target.value)}
                            >
                                <option value="Pending">Pending</option>
                                <option value="In progress">In progress</option>
                                <option value="Completed">Completed</option>
                            </select>
                            {err("status")}
                        </div>

                        {/* Created by */}
                        <div className="form-group">
                            <label className="form-label">Created by <span className="required">*</span></label>
                            <select
                                className={inputCls("createdBy")}
                                value={form.createdBy}
                                onChange={e => handleChange("createdBy", e.target.value)}
                            >
                                <option value="">Select creator</option>
                                {CREATORS.map(c => <option key={c} value={c}>{c}</option>)}
                            </select>
                            {err("createdBy")}
                        </div>
                    </div>
                </div>

                <div className="modal-footer">
                    <button className="btn btn-secondary" onClick={onClose}>Cancel</button>
                    <button className="btn btn-primary" onClick={handleSubmit}>
                        {initialData ? "Update" : "Submit"}
                    </button>
                </div>
            </div>
        </div>
    )
}

export default OrderForm
